                .map { id in availableMics.contains(where: { $0.id == id }) } ?? false
            let newSelectedMicID = currentMicStillAvailable
                ? currentMicID
                : availableMics.first(where: { $0.isDefault })?.id ?? availableMics.first?.id
            selectedMicID = newSelectedMicID

